import org.springframework.stereotype.Controller;
import org.springframework.web.bind.annotation.GetMapping;

@Controller
public class LogoutController {
    
    @GetMapping("/logout")
    public String logout(String next) {
        if (next == null || next.isEmpty())  // Default to home page after logout is successful, change this accordingly based on your requirement and application setup.
            return "redirect:/";  
            
         else    
              return "redirect:" + next;    // Redirection using the 'next' parameter that was set by SSO system when logging out from any service provider or identity Provider (IDP).  It will be handled at IDP side based on what kind of logout is performed. If you are configuring it manually then use this approach, else if configured properly with OAuth2 protocol for Single Sign-Out(SSO) we should redirect back to '/' using 'next'.
    }  
}